import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    private static int findKth(int[] a, int[] b, int k) {
        int m = a.length, n = b.length;
        if (m > n) return findKth(b, a, k);
        int low = Math.max(0, k - n);
        int high = Math.min(k, m);
        while (low <= high) {
            int cut1 = low + (high - low) / 2;
            int cut2 = k - cut1;
            int l1 = (cut1 == 0) ? Integer.MIN_VALUE : a[cut1 - 1];
            int l2 = (cut2 == 0) ? Integer.MIN_VALUE : b[cut2 - 1];
            int r1 = (cut1 == m) ? Integer.MAX_VALUE : a[cut1];
            int r2 = (cut2 == n) ? Integer.MAX_VALUE : b[cut2];
            if (l1 <= r2 && l2 <= r1) {
                return Math.max(l1, l2);
            } else if (l1 > r2) {
                high = cut1 - 1;
            } else {
                low = cut1 + 1;
            }
        }
        return -1; // should never reach here
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in, StandardCharsets.UTF_8));
        // Read entire input, replace literal "\n" with spaces to handle escaped newlines in test data
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        String data = raw.toString().replace("\\n", " ");
        Scanner sc = new Scanner(data);
        int T = sc.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int M = sc.nextInt();
            int N = sc.nextInt();
            int[] A = new int[M];
            for (int i = 0; i < M; i++) A[i] = sc.nextInt();
            int[] B = new int[N];
            for (int i = 0; i < N; i++) B[i] = sc.nextInt();
            int K = sc.nextInt();
            sb.append(findKth(A, B, K)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

